#!/usr/bin/env python3
# Piece 1c-cache (dream-os) — prompt caching. The biggest cost win in the build.
#
# Root cause of the inflated per-turn cost (27k+ input tokens for a simple log):
# Kriya's ~5k-token system (soul + 22-tool bench) and Myra's ~1.9k soul were
# re-sent at FULL input price on every model iteration — several per turn. They
# are byte-identical every call, so they should be CACHED.
#
# Fix: system becomes a block-array — the stable soul/bench in an ephemeral
# cache_control block (re-read at ~10% input price within the cache window), the
# volatile dated line (today/clock) in its own UNCACHED block so the daily date
# change never busts the cache. Kriya's tool bench is cached via cache_control on
# its last tool (caches every tool def before it).
#
# Expected: repeat turns drop from ~Rs 3 toward sub-rupee. Pure plumbing — the
# dual-soul architecture was never the cost.
#
# Overwrites myraLoop.js + kriyaTurn.js.

import base64, os, sys
ROOT=os.getcwd()
PAYLOADS={
    'src/agent/myraLoop.js': '',
    'src/agent/kriyaTurn.js': '',
}
def main():
    if not os.path.isdir(os.path.join(ROOT,"src","agent")):
        print("ERROR: run from dream-os repo root."); sys.exit(1)
    for rel,b64 in PAYLOADS.items():
        open(os.path.join(ROOT,rel),"wb").write(base64.b64decode(b64)); print(f"OK: overwrote {rel}")
    print("\nPiece 1c-cache written. Souls + bench now cached; repeat turns bill the stable prefix at ~10%.")
if __name__=="__main__": main()
